import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel.EstimationTier;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.OptimizationGoal;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.PhysicalProperties;
import org.junit.jupiter.api.Test;

class PlanTemplateCacheTest {
	@Test
	void keyIncludesGoalConfigurationAndStatisticsVersion() {
		PlanTemplateCache<String> cache = new PlanTemplateCache<>(8);
		PlanTemplateCache.Configuration config = new PlanTemplateCache.Configuration(true, 14, 100_000L,
				EstimationTier.STANDARD);
		OptimizationGoal bagGoal = OptimizationGoal.root();
		PlanTemplateCache.Key base = new PlanTemplateCache.Key(List.of("a", "b"), Set.of("seed"), bagGoal, config,
				6L);
		cache.put(base, "plan");

		assertEquals("plan", cache.get(base).orElseThrow());
		assertTrue(cache.get(new PlanTemplateCache.Key(base.factorFingerprints(), base.initialBoundVars(),
				bagGoal.withRequiredProperties(PhysicalProperties.ANY.withOrdering(List.of("seed"))), config, 6L))
				.isEmpty());
		assertTrue(cache.get(new PlanTemplateCache.Key(base.factorFingerprints(), base.initialBoundVars(), bagGoal,
				new PlanTemplateCache.Configuration(true, 14, 10L, EstimationTier.STANDARD), 6L)).isEmpty());
		assertTrue(cache.get(new PlanTemplateCache.Key(base.factorFingerprints(), base.initialBoundVars(), bagGoal,
				config, 7L)).isEmpty());
	}
}
